53	  out_box_num = 0;
54	  int sizeOut = layer_size * layer_size;
55	  const float det_scale = 0.1f; 
56	  const float conf_thresh = 0.9f;  
57	  float ct = -logf(1.0f / conf_thresh - 1.0f) / det_scale;
58	  int32_t conf_thresh_inverse = (int32_t)floorf(ct);
